#include<bits/stdc++.h>
using namespace std;

int main(){
    int x,a[100001],n,num=0;
    cin>>n;
    for(int i=0;i<n;i++){
        cin>>a[i];
    }cin>>x;
    for(int i=0;i<n;i++)
    {
        if(x>=a[i]){
            x-=a[i];
            num++;
        }


    }cout<<num;

    return 0;
}
